import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const query = "2026 FIFA World Cup winner";

  const search = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query,
      category: "sports",
      sortBy: "volume",
    },
  });

  const searchOutcomes = Array.isArray(search?.outcomes) ? search.outcomes : [];
  const directSlug = search?.eventSlug;
  const directTitle = search?.eventTitle;
  const directConfidence = search?.matchConfidence;

  let resolvedSlug = directSlug;
  let resolutionPath = "search_and_get_outcomes";

  if (!resolvedSlug || (directConfidence !== "exact" && directConfidence !== "high")) {
    const fallbackSearch = await callMcpSkill({
      toolId,
      toolName: "search_markets",
      args: {
        query,
        limit: 10,
        status: "live",
        category: "sports",
      },
    });

    const candidates = Array.isArray(fallbackSearch?.results) ? fallbackSearch.results : [];
    const ranked = pickTopSemanticCandidates({
      target: "2026 FIFA World Cup winner event",
      candidates,
      requiredTerms: ["world cup", "winner"],
      avoidTerms: ["qualifier", "group", "division"],
      limit: 1,
    });

    const best = Array.isArray(ranked) ? ranked[0] : null;
    if (best && best.slug) {
      resolvedSlug = best.slug;
      resolutionPath = "search_markets + pickTopSemanticCandidates";
    }
  }

  if (!resolvedSlug) {
    return {
      error: "No eventSlug could be resolved",
      searchResult: {
        eventTitle: directTitle,
        matchConfidence: directConfidence,
        searchMethod: search?.searchMethod,
        totalOutcomes: search?.totalOutcomes,
      },
      attemptedBranches: ["search_and_get_outcomes", "search_markets + pickTopSemanticCandidates"],
      stopReason: "missingEventSlug",
    };
  }

  const eventData = await callMcpSkill({
    toolId,
    toolName: "get_event_by_slug",
    args: {
      slug: resolvedSlug,
    },
  });

  const eventId = eventData?.event?.id;
  const eventTitle = eventData?.event?.title || directTitle || query;
  const markets = Array.isArray(eventData?.markets) ? eventData.markets : [];

  if (!eventId) {
    return {
      error: "get_event_by_slug did not return an event id",
      resolvedSlug,
      eventTitle,
      marketsReturned: markets.length,
      resolutionPath,
      stopReason: "missingEventId",
    };
  }

  const volumeBatch = await callMcpSkillsParallel({
    label: "event-volume-followup",
    calls: [
      {
        key: "liveVolume",
        toolId,
        toolName: "get_event_live_volume",
        args: {
          eventId,
        },
      },
    ],
  });

  const liveVolumeResult =
    volumeBatch?.results?.find((entry) => entry.key === "liveVolume")?.status === "fulfilled"
      ? volumeBatch.results.find((entry) => entry.key === "liveVolume").value
      : null;

  const liveMarkets = Array.isArray(liveVolumeResult?.markets) ? liveVolumeResult.markets : [];
  const total = typeof liveVolumeResult?.total === "number" ? liveVolumeResult.total : null;

  const topThree = liveMarkets
    .filter((m) => m && typeof m.market === "string" && typeof m.value === "number")
    .sort((a, b) => b.value - a.value)
    .slice(0, 3)
    .map((m, index) => ({
      rank: index + 1,
      market: m.market,
      value: m.value,
      shareOfEventTotal: total && total !== 0 ? m.value / total : null,
      shareOfEventTotalPercent: total && total !== 0 ? (m.value / total) * 100 : null,
    }));

  return {
    eventTitle,
    resolvedSlug,
    eventId,
    resolutionPath,
    topThreeSubmarketsByLiveVolumeShare: topThree,
    totalLiveVolume: total,
    sourceCounts: {
      searchOutcomes: searchOutcomes.length,
      eventMarkets: markets.length,
      liveVolumeMarkets: liveMarkets.length,
    },
    fetchedAt: liveVolumeResult?.fetchedAt || eventData?.fetchedAt || search?.fetchedAt,
  };
}

